SELECT id, patient_id, meal_date, meal_type, food_content, nutrition_notes, created_at
FROM dietary_advice
WHERE id = #{id}

SELECT id, patient_id, meal_date, meal_type, food_content, nutrition_notes, created_at
FROM dietary_advice
WHERE patient_id = #{patientId}
  AND meal_date = #{mealDate}
ORDER BY FIELD(meal_type, 'BREAKFAST', 'LUNCH', 'DINNER', 'SNACK'), id
